 import java.util.Collections;

  import sailpoint.object.Filter;
  import sailpoint.object.Identity;
  import sailpoint.object.QueryOptions;
  import sailpoint.tools.Util;
  import sailpoint.api.SailPointContext;

  import sailpoint.object.EmailOptions;
  import sailpoint.object.EmailTemplate;
  import sailpoint.object.Custom;
  import java.text.ParseException;
  import java.text.SimpleDateFormat;
  import java.util.ArrayList;
  import java.util.Calendar;
  import java.util.Date;
  import java.util.GregorianCalendar;
  import java.util.List;
  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;	

  static Log logger = LogFactory.getLog("Rule.Ascension-Rule-Termination-Reminder");

  logger.debug("Ascension-Rule-Termination-Reminder");

	/** check the the expire date of identity is within the given list
	 * @param expireDateString , reminderDaysList
	 * @return boolean true when advance the today date by any of the given date
	 */
  public static boolean isEmailTrigger(String expireDateString,List reminderDaysList){
    String methodName = "isEmailTrigger";
    logger.info("Enter "+methodName);
    boolean result = false;
    try{

      Date expireDate = convertStringToDate(expireDateString);

      if(expireDate!=null){
        GregorianCalendar today = (GregorianCalendar) GregorianCalendar.getInstance();
        GregorianCalendar todayCal = (GregorianCalendar) GregorianCalendar.getInstance();
        GregorianCalendar expireDateCal = (GregorianCalendar) GregorianCalendar.getInstance();

        today.set(GregorianCalendar.HOUR,0);
        today.set(GregorianCalendar.MINUTE,0);
        today.set(GregorianCalendar.SECOND,0);
        today.set(GregorianCalendar.MILLISECOND ,0);
        today.set(GregorianCalendar.HOUR_OF_DAY,0);

        logger.debug("today "+today.getTime());

        expireDateCal.setTime(expireDate);
        expireDateCal.set(GregorianCalendar.HOUR,0);
        expireDateCal.set(GregorianCalendar.MINUTE,0);
        expireDateCal.set(GregorianCalendar.SECOND,0);
        expireDateCal.set(GregorianCalendar.MILLISECOND ,0);
        expireDateCal.set(GregorianCalendar.HOUR_OF_DAY,0);

        logger.debug("expireDateCal "+expireDateCal.getTime());

        for(String dayRange : reminderDaysList){
          try{
            if(Util.isNotNullOrEmpty(dayRange)){
              dayRange = dayRange.trim();
            }else{
              dayRange = "";
            }
            todayCal.setTime(today.getTime());
            todayCal.add(GregorianCalendar.DATE, Integer.parseInt(dayRange));
            if (todayCal.equals(expireDateCal)) {
              logger.debug("reminder " + dayRange);
              result = true;
              break;
            }
          }catch(NumberFormatException ne){
            continue;
          }
        }
      }
    }catch(Exception ex){
      logger.error("Exception in "+methodName+" : "+ex.getMessage());
    }
    logger.info("Exit "+methodName);
    return result;
  }


  public static String cmEmail(String cmName){

     String cmEmail = null;
     Identity identity = context.getObjectByName(Identity.class,cmName);
     if(Util.isNotNullOrEmpty(cmName)){
      Identity cmId = context.getObjectByName(Identity.class,cmName);
      cmEmail = cmId.getEmail() == null ? ""  : cmId.getEmail();
	   }
  
  	return cmEmail;
  }

  logger.debug("Ascension-Rule-Termination-Reminder Starting");




  List&lt;String> reminderDays = new ArrayList();
  List contractorTypes = new ArrayList();

  Custom customObj = context.getObjectByName(Custom.class,"Ascension-Custom-ContractorConfiguration");
  if(customObj!=null) {
    if(customObj.get("TerminationReminderDays") !=null ){
      String terminationReminderDays = customObj.get("TerminationReminderDays");
      reminderDays = sailpoint.tools.Util.csvToList(terminationReminderDays);
    } else{
      throw new Exception("Entry(TerminationReminderDays) not configure. Look into custom.");
    }
    if(customObj.get("ContractorType") !=null ){
      contractorTypes = customObj.get("ContractorType");
    }else{
      throw new Exception("Entry(ContractorType) not configure. Look into custom.");
    }
    //comment decache //context.decache(customObj);
  }else{
      throw new Exception("Invalide Custom object. Not found in sailpoint.");
  }


  Map args = new HashMap();

  EmailTemplate template = context.getObjectByName(EmailTemplate.class, "Ascension-EmailTemplate-TerminationAdvanceNotification");
  if(template==null){
    throw new Exception("Invalid EmailTemplate. Not found in sailpoint.");
  }


  QueryOptions qo = new QueryOptions();  
  EmailOptions options = new EmailOptions();
  qo.addFilter( Filter.ignoreCase( Filter.in("type", contractorTypes)));
  qo.addFilter(Filter.eq("inactive", false));
  qo.setCloneResults(true);
  Iterator allIdentityItr = context.search(Identity.class, qo);  
	List toEmailList = new ArrayList();
  while (allIdentityItr!=null && allIdentityItr.hasNext()) {

    Identity identityObj = allIdentityItr.next();
    
    if(identityObj!=null && identityObj.getManager()!=null && !identityObj.getManager().isInactive()  &&  Util.isNotNullOrEmpty( identityObj.getManager().getEmail()) ) {
      if(identityObj.getStringAttribute("ctrexpDt") !=null ){
        // send email 
        try{
          if(isEmailTrigger(identityObj.getStringAttribute("ctrexpDt") ,reminderDays )){
            String cmEmailAddr = null;
            String contractorManager = identityObj.getAttribute("contractorManager");
            toEmailList.add(identityObj.getManager().getEmail());
            cmEmailAddr = cmEmail(contractorManager);
            if( Util.isNotNullOrEmpty(cmEmailAddr)){
              toEmailList.add(cmEmailAddr);
            }
            
            
            options.setTo(toEmailList);
       			args.put("identityName",identityObj.getName());
						args.put("identityDisplayName",identityObj.getDisplayName());
            args.put("expireDate",identityObj.getStringAttribute("ctrexpDt"));
            options.setVariables(args);
            context.sendEmailNotification(template,options);
          }
        }catch(Exception ex){
         	logger.error("Exception in sending user account termination reminder."+ex.getMessage());
        }
      }
      //comment decache //context.decache(identityObj);
    }

  }

  if(allIdentityItr != null) {
    Util.flushIterator(allIdentityItr);
  }

  //comment decache //context.decache(template);

  logger.debug("Ascension-Rule-Termination-Reminder Ending.");

  return "success";
